scripts.content:
extends Node

## Quest state machine: locked → available → active → completed → (failed)

signal quest_accepted(quest_id: String)
signal quest_completed(quest_id: String)
signal quest_failed(quest_id: String)
signal objective_updated(quest_id: String, objective_id: String, current: int, target: int)
signal quest_stage_advanced(quest_id: String, stage: int)
signal quest_available(quest_id: String)
signal reward_granted(quest_id: String, rewards: Dictionary)
signal ui_update  ## Emitted when quest log should refresh

enum QuestState { LOCKED, AVAILABLE, ACTIVE, COMPLETED, FAILED }

var _quests: Dictionary = {}  ## quest_id → {state, stage, objectives, data}
var _completed_once: Array[String] = []

func _ready():
	_load_quest_data()

func _load_quest_data() -> void:
	var dir := DirAccess.open("{{quest_data_path}}")
	if dir == null:
		push_warning("Quest data directory not found: {{quest_data_path}}")
		return
	dir.list_dir_begin()
	var file_name := dir.get_next()
	while file_name != "":
		if file_name.ends_with(".tres") or file_name.ends_with(".json"):
			var quest := _load_quest_file("{{quest_data_path}}/%s" % file_name)
			if not quest.is_empty():
				var id := quest.get("id", file_name.get_basename())
				_quests[id] = {"state": QuestState.LOCKED, "stage": 0, "objectives": {}, "data": quest}
				_check_unlock_conditions(id)
		file_name = dir.get_next()

func _load_quest_file(path: String) -> Dictionary:
	var file := FileAccess.open(path, FileAccess.READ)
	if file == null:
		return {}
	var json := JSON.new()
	var err := json.parse(file.get_as_text())
	file.close()
	if err != OK:
		push_error("Failed to parse quest file: %s" % path)
		return {}
	return json.get_data()

func accept_quest(quest_id: String) -> bool:
	if not _quests.has(quest_id):
		push_error("Unknown quest: %s" % quest_id)
		return false
	if _quests[quest_id].state != QuestState.AVAILABLE:
		return false

	var active_count := 0
	for q in _quests.values():
		if q.state == QuestState.ACTIVE:
			active_count += 1
	if active_count >= {{max_active_quests}}:
		push_warning("Max active quests reached")
		return false

	_quests[quest_id].state = QuestState.ACTIVE
	_quests[quest_id].stage = 0
	_init_objectives(quest_id)
	quest_accepted.emit(quest_id)
	if {{enable_quest_log}}:
		ui_update.emit()
	return true

func complete_quest(quest_id: String) -> bool:
	if not _quests.has(quest_id) or _quests[quest_id].state != QuestState.ACTIVE:
		return false

	_quests[quest_id].state = QuestState.COMPLETED
	_completed_once.append(quest_id)
	_grant_rewards(quest_id)
	quest_completed.emit(quest_id)

	# Unlock dependent quests
	_unlock_children(quest_id)

	if {{enable_quest_log}}:
		ui_update.emit()
	return true

func fail_quest(quest_id: String) -> bool:
	if not _quests.has(quest_id) or _quests[quest_id].state != QuestState.ACTIVE:
		return false

	_quests[quest_id].state = QuestState.FAILED
	quest_failed.emit(quest_id)
	if {{enable_quest_log}}:
		ui_update.emit()
	return true

func advance_objective(quest_id: String, objective_id: String, amount: int = 1) -> void:
	if not _quests.has(quest_id) or _quests[quest_id].state != QuestState.ACTIVE:
		return

	var objectives := _quests[quest_id].objectives
	if not objectives.has(objective_id):
		return

	var obj := objectives[objective_id]
	if obj.get("completed", false):
		return

	obj.current = min(obj.current + amount, obj.target)
	objective_updated.emit(quest_id, objective_id, obj.current, obj.target)

	if obj.current >= obj.target:
		obj.completed = true
		_check_stage_completion(quest_id)

func advance_quest_stage(quest_id: String, stage: int) -> void:
	if not _quests.has(quest_id) or _quests[quest_id].state != QuestState.ACTIVE:
		return
	_quests[quest_id].stage = stage
	_init_objectives(quest_id, stage)
	quest_stage_advanced.emit(quest_id, stage)

func get_quest_state(quest_id: String) -> int:
	if not _quests.has(quest_id):
		return -1
	return _quests[quest_id].state

func is_quest_completed(quest_id: String) -> bool:
	return quest_id in _completed_once

func get_active_quests() -> Array[Dictionary]:
	var active: Array[Dictionary] = []
	for id in _quests:
		if _quests[id].state == QuestState.ACTIVE:
			active.append({
				"id": id,
				"title": _quests[id].data.get("title", id),
				"stage": _quests[id].stage,
				"objectives": _quests[id].objectives.duplicate(),
			})
	return active

func get_available_quests() -> Array[Dictionary]:
	var available: Array[Dictionary] = []
	for id in _quests:
		if _quests[id].state == QuestState.AVAILABLE:
			available.append({
				"id": id,
				"title": _quests[id].data.get("title", id),
				"description": _quests[id].data.get("description", ""),
				"level": _quests[id].data.get("level", 1),
			})
	return available

func trigger_event(event_id: String) -> void:
	"""Notify quests of a world event (e.g. 'npc_spoken:eldrin', 'item_acquired:ancient_key')."""
	for quest_id in _quests:
		if _quests[quest_id].state == QuestState.ACTIVE:
			var data := _quests[quest_id].data
			var stages := data.get("stages", [])
			var stage_idx := _quests[quest_id].stage
			if stage_idx < stages.size():
				var objectives := stages[stage_idx].get("objectives", [])
				for obj in objectives:
					if obj.get("type", "") == "event" and obj.get("event_id", "") == event_id:
						advance_objective(quest_id, obj.get("id", ""), 1)

func _init_objectives(quest_id: String, stage: int = 0) -> void:
	var data := _quests[quest_id].data
	var stages := data.get("stages", [])
	if stage >= stages.size():
		complete_quest(quest_id)
		return

	_quests[quest_id].objectives.clear()
	for obj in stages[stage].get("objectives", []):
		_quests[quest_id].objectives[obj.id] = {
			"id": obj.id,
			"description": obj.get("description", ""),
			"target": obj.get("target", 1),
			"current": 0,
			"completed": false,
			"type": obj.get("type", "default"),
		}

func _check_stage_completion(quest_id: String) -> void:
	var objectives := _quests[quest_id].objectives
	for obj in objectives.values():
		if not obj.get("completed", false):
			return
	advance_quest_stage(quest_id, _quests[quest_id].stage + 1)

func _check_unlock_conditions(quest_id: String) -> void:
	var data := _quests[quest_id].data
	var prereqs := data.get("prerequisites", [])
	for prereq in prereqs:
		var pq_id := prereq.get("quest_id", "")
		if not is_quest_completed(pq_id):
			return
	_quests[quest_id].state = QuestState.AVAILABLE
	quest_available.emit(quest_id)

func _unlock_children(quest_id: String) -> void:
	for id in _quests:
		if _quests[id].state == QuestState.LOCKED:
			var prereqs := _quests[id].data.get("prerequisites", [])
			for prereq in prereqs:
				if prereq.get("quest_id", "") == quest_id:
					_check_unlock_conditions(id)
					break

func _grant_rewards(quest_id: String) -> void:
	var data := _quests[quest_id].data
	var rewards := data.get("rewards", {})
	if rewards.is_empty():
		return

	reward_granted.emit(quest_id, rewards)

	# XP
	if rewards.has("xp"):
		var player := get_tree().get_first_node_in_group("player")
		if player and player.has_method("add_xp"):
			player.add_xp(rewards.xp)

	# Items
	if rewards.has("items"):
		var inv := get_tree().get_first_node_in_group("inventory")
		if inv and inv.has_method("add_item"):
			for item in rewards.items:
				inv.add_item(item.id, item.get("count", 1))

	# Currency
	if rewards.has("currency"):
		var player := get_tree().get_first_node_in_group("player")
		if player and player.has_method("add_currency"):
			player.add_currency(rewards.currency)

func serialize() -> Dictionary:
	var state := {}
	for id in _quests:
		state[id] = {
			"state": _quests[id].state,
			"stage": _quests[id].stage,
			"objectives": _quests[id].objectives.duplicate(),
		}
	return {"quests": state, "completed": _completed_once.duplicate()}

func deserialize(data: Dictionary) -> void:
	var quests := data.get("quests", {})
	for id in quests:
		if _quests.has(id):
			_quests[id].state = quests[id].get("state", QuestState.LOCKED)
			_quests[id].stage = quests[id].get("stage", 0)
			_quests[id].objectives = quests[id].get("objectives", {})
	_completed_once = data.get("completed", [])
